   103→
   104→/// Arguments for saddle command
   105→#[derive(Debug)]
   106→pub struct jjrq_SaddleArgs {
   107→    pub file: std::path::PathBuf,
   108→    pub firemark: Firemark,
   109→}
   110→
   111→/// Output structure for saddle command
   112→#[derive(Serialize)]
   113→pub(crate) struct zjjrq_SaddleOutput {
   114→    pub(crate) heat_silks: String,
   115→    pub(crate) paddock_file: String,
   116→    pub(crate) paddock_content: String,
   117→    #[serde(skip_serializing_if = "Option::is_none")]
   118→    pub(crate) pace_coronet: Option<String>,
   119→    #[serde(skip_serializing_if = "Option::is_none")]
   120→    pub(crate) pace_silks: Option<String>,
