   130→/// Run the saddle command - return Heat context
   131→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   132→    let gallops = match Gallops::jjrg_load(&args.file) {
   133→        Ok(g) => g,
   134→        Err(e) => {
   135→            eprintln!("jjx_saddle: error: {}", e);
   136→            return 1;
   137→        }
   138→    };
   139→
   140→    let heat_key = args.firemark.jjrf_display();
   141→    let heat = match gallops.heats.get(&heat_key) {
   142→        Some(h) => h,
   143→        None => {
   144→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   145→            return 1;
   146→        }
   147→    };
   148→
   149→    // Check if heat is stabled (cannot saddle stabled heat)
   150→    if heat.status == HeatStatus::Stabled {
   151→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   152→        return 1;
   153→    }
   154→
   155→    // Read paddock file content
   156→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   157→        Ok(content) => content,
   158→        Err(e) => {
   159→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   160→            return 1;
   161→        }
   162→    };
   163→
   164→    // Get recent steeplechase entries
   165→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   166→        firemark: args.firemark.jjrf_as_str().to_string(),
   167→        limit: 10,
   168→    }).unwrap_or_default();
   169→
   170→    // Find first actionable pace (rough or bridled)
   171→    let mut output = zjjrq_SaddleOutput {
   172→        heat_silks: heat.silks.clone(),
   173→        paddock_file: heat.paddock_file.clone(),
   174→        paddock_content,
   175→        pace_coronet: None,
   176→        pace_silks: None,
   177→        pace_state: None,
   178→        spec: None,
   179→        direction: None,
   180→        recent_work,
   181→    };
   182→
   183→    for coronet_key in &heat.order {
   184→        if let Some(pace) = heat.paces.get(coronet_key) {
   185→            if let Some(tack) = pace.tacks.first() {
   186→                match tack.state {
   187→                    PaceState::Rough | PaceState::Bridled => {
   188→                        output.pace_coronet = Some(coronet_key.clone());
   189→                        output.pace_silks = Some(tack.silks.clone());
   190→                        output.pace_state = Some(match tack.state {
   191→                            PaceState::Rough => "rough".to_string(),
   192→                            PaceState::Bridled => "bridled".to_string(),
   193→                            _ => unreachable!(),
   194→                        });
   195→                        output.spec = Some(tack.text.clone());
   196→                        if tack.state == PaceState::Bridled {
   197→                            output.direction = tack.direction.clone();
   198→                        }
   199→                        break;
   200→                    }
   201→                    _ => continue,
   202→                }
   203→            }
   204→        }
   205→    }
   206→
   207→    // Output JSON
   208→    match serde_json::to_string_pretty(&output) {
   209→        Ok(json) => {
   210→            println!("{}", json);
   211→            0
   212→        }
   213→        Err(e) => {
   214→            eprintln!("jjx_saddle: error serializing output: {}", e);
   215→            1
   216→        }
   217→    }
   218→}
