   378→/// Helper to resolve pace by coronet or silks
   379→///
   380→/// First tries to parse pace_arg as a Coronet and lookup by coronet key.
   381→/// If that fails, iterates heat.paces to find a pace where tacks[0].silks matches pace_arg.
   382→/// Returns tuple of (coronet_key, pace_ref) if found.
   383→fn zjjrq_resolve_pace<'a>(
   384→    heat: &'a crate::jjrg_gallops::jjrg_Heat,
   385→    pace_arg: &str,
   386→) -> Option<(&'a String, &'a Pace)> {
   387→    // Try parsing as Coronet first
   388→    if let Ok(coronet) = Coronet::jjrf_parse(pace_arg) {
   389→        let coronet_key = coronet.jjrf_display();
   390→        if let Some((key, pace)) = heat.paces.get_key_value(&coronet_key) {
   391→            return Some((key, pace));
   392→        }
   393→    }
   394→
   395→    // Fallback: search by silks
   396→    for (coronet_key, pace) in &heat.paces {
   397→        if let Some(tack) = pace.tacks.first() {
   398→            if tack.silks == pace_arg {
   399→                return Some((coronet_key, pace));
   400→            }
   401→        }
   402→    }
   403→
   404→    None
   405→}
   406→
   407→/// Helper to convert PaceState to display string
   408→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   409→    match state {
   410→        PaceState::Rough => "rough",
   411→        PaceState::Bridled => "bridled",
   412→        PaceState::Complete => "complete",
   413→        PaceState::Abandoned => "abandoned",
   414→    }
   415→}
