   417→// ============================================================================
   418→// Scout - Search across heats and paces with regex
   419→// ============================================================================
   420→
   421→/// Arguments for scout command
   422→#[derive(Debug)]
   423→pub struct jjrq_ScoutArgs {
   424→    pub file: std::path::PathBuf,
   425→    pub pattern: String,
   426→    pub actionable: bool,
   427→}
   428→
   429→/// Run the scout command - regex search across heats/paces
   430→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   431→    use regex::RegexBuilder;
   432→
   433→    let gallops = match Gallops::jjrg_load(&args.file) {
   434→        Ok(g) => g,
   435→        Err(e) => {
   436→            eprintln!("jjx_scout: error: {}", e);
   437→            return 1;
   438→        }
   439→    };
   440→
   441→    // Build case-insensitive regex
   442→    let re = match RegexBuilder::new(&args.pattern)
   443→        .case_insensitive(true)
   444→        .build()
   445→    {
   446→        Ok(r) => r,
   447→        Err(e) => {
   448→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   449→            return 1;
   450→        }
   451→    };
   452→
   453→    // Track which heats have matches (for group headers)
   454→    let mut current_heat_key: Option<String> = None;
   455→
   456→    // Iterate all heats (racing, stabled, retired)
   457→    for (heat_key, heat) in &gallops.heats {
   458→        // Search each pace in order
   459→        for coronet_key in &heat.order {
   460→            if let Some(pace) = heat.paces.get(coronet_key) {
   461→                if let Some(tack) = pace.tacks.first() {
   462→                    // Apply actionable filter if requested
   463→                    if args.actionable {
   464→                        match tack.state {
   465→                            PaceState::Rough | PaceState::Bridled => {},
   466→                            _ => continue,
   467→                        }
   468→                    }
   469→
   470→                    // Search: silks, spec (tack text), direction, paddock content
   471→                    // Use owned strings to avoid lifetime issues
   472→                    let mut match_result: Option<(String, String)> = None;
   473→
   474→                    if re.is_match(&tack.silks) {
   475→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   476→                    } else if re.is_match(&tack.text) {
   477→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   478→                    } else if let Some(ref direction) = tack.direction {
   479→                        if re.is_match(direction) {
   480→                            match_result = Some(("direction".to_string(), direction.clone()));
   481→                        }
   482→                    } else {
   483→                        // Search paddock content
   484→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   485→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   486→                            if re.is_match(&content) {
   487→                                match_result = Some(("paddock".to_string(), content));
   488→                            }
   489→                        }
   490→                    }
   491→
   492→                    // If we found a match, output it
   493→                    if let Some((field_name, field_content)) = match_result {
   494→                        // Print heat header if this is a new heat
   495→                        if current_heat_key.as_ref() != Some(heat_key) {
   496→                            println!("{} {}", heat_key, heat.silks);
   497→                            current_heat_key = Some(heat_key.clone());
   498→                        }
   499→
   500→                        // Print pace line
   501→                        let state_str = zjjrq_pace_state_str(&tack.state);
   502→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   503→
   504→                        // Print match line with context (extract ~60 chars around match)
   505→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   506→                        println!("    {}: {}", field_name, match_excerpt);
   507→                    }
   508→                }
   509→            }
   510→        }
   511→    }
   512→
   513→    0
   514→}
   515→
   516→/// Extract context around the first regex match in content
   517→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   518→    if let Some(mat) = re.find(content) {
   519→        let start = mat.start();
   520→        let end = mat.end();
   521→
   522→        // Find context window (30 chars before, 30 chars after)
   523→        let context_before = 30;
   524→        let context_after = 30;
   525→
   526→        let window_start = start.saturating_sub(context_before);
   527→        let window_end = (end + context_after).min(content.len());
   528→
   529→        let mut excerpt = String::new();
   530→        if window_start > 0 {
   531→            excerpt.push_str("...");
   532→        }
   533→        excerpt.push_str(&content[window_start..window_end]);
   534→        if window_end < content.len() {
   535→            excerpt.push_str("...");
   536→        }
   537→
   538→        // Replace newlines with spaces for single-line display
   539→        excerpt.replace('\n', " ").replace('\r', "")
   540→    } else {
   541→        // Shouldn't happen, but fallback to truncated content
   542→        let truncated = content.chars().take(60).collect::<String>();
   543→        if content.len() > 60 {
   544→            format!("{}...", truncated)
   545→        } else {
   546→            truncated
   547→        }
   548→    }
   549→}
